// AI Agent가 전달한 query를 추출하고 URL을 생성
// ToolWorkflow input 구조: { query: '...' }
const raw = $input.first().json;
const query = (raw.query || raw.keyword || raw.input || '').trim();

if (!query) {
  return [{ json: { url: '', query: '', isEmpty: true } }];
}

// 한글 포함 keyword URL 인코딩
const encodedKeyword = encodeURIComponent(query);
const url = 'https://www.foreverlove.co.kr/list/open_api.html?mode=search&type=product&keyword=' + encodedKeyword + '&limit=5';

return [{ json: { url: url, query: query, isEmpty: false } }];

// 메이크샵 상품 검색 결과 파싱
// 응답 구조: { return_code, totalCount, list: [{ uid, product_name, sellprice, display, sell_accept }] }
// n8n HTTP Request 노드가 JSON을 문자열(data 키)로 반환하는 경우 파싱 처리
const query = $('Code: 검색 URL 준비').first().json.query || '';
const isEmpty = $('Code: 검색 URL 준비').first().json.isEmpty;
const baseUrl = 'https://www.foreverlove.co.kr';
const fallbackUrl = baseUrl + '/goods/goods_search.php?keyword=' + encodeURIComponent(query);

// query가 비어있는 경우
if (isEmpty || !query) {
  return [{ json: { response: '검색할 상품명을 알려주시면 찾아드릴게요 🌸' } }];
}

const rawInput = $input.first().json;
// n8n이 응답 본문을 data 문자열로 감싸는 경우 JSON.parse 처리
const searchResult = (rawInput.data && typeof rawInput.data === 'string')
  ? JSON.parse(rawInput.data)
  : rawInput;

// 검색 실패 처리
if (searchResult.error || (searchResult.return_code && searchResult.return_code !== '0000')) {
  return [{ json: { response: '상품 검색에 일시적인 오류가 발생했어요 🌿 자사몰에서 직접 검색해 보세요!\n' + fallbackUrl } }];
}

const list = searchResult.list || [];

// 판매 중이고 진열된 상품만 필터링
const available = list.filter(function(p) {
  return p.display === 'Y' && p.sell_accept === 'Y';
});

if (available.length === 0) {
  return [{ json: { response: '"' + query + '" 검색 결과가 없어요 🌿 다른 키워드로 자사몰에서 찾아보세요!\n' + fallbackUrl } }];
}

// 상위 3개 상품 포맷
const top3 = available.slice(0, 3);
const lines = top3.map(function(p) {
  const name = p.product_name || '상품명 없음';
  const price = p.sellprice ? Number(p.sellprice).toLocaleString('ko-KR') + '원' : '';
  const url = p.uid ? baseUrl + '/goods/goods_view.php?goodsno=' + p.uid : '';
  return name + (price ? ' — ' + price : '') + (url ? '\n' + url : '');
});

const response = '"' + query + '" 관련 상품이에요 🌸\n\n' + lines.join('\n\n');
return [{ json: { response: response } }];
